#include <stdio.h>
int main() {
    int U, V, W, X, K;
    scanf("%d %d %d %d %d", &U, &V, &W, &X, &K);
    int A[U][V], B[W][X];
    for (int i = 0; i < U; i++) {
        for (int j = 0; j < V; j++) {
            scanf("%d", &A[i][j]);
        }
    }
    for (int i = 0; i < W; i++) {
        for (int j = 0; j < X; j++) {
            scanf("%d", &B[i][j]);
        }
    }
    int count = 0;
    for (int i = 0; i <= U - K; i++) {
        for (int j = 0; j <= V - K; j++) {
            for (int x = 0; x <= W - K; x++) {
                for (int y = 0; y <= X - K; y++) {
                    int identical = 1;
                    for (int k = 0; k < K; k++) {
                        for (int l = 0; l < K; l++) {
                            if (A[i + k][j + l] != B[x + k][y + l]) {
                                identical = 0;
                                break;
                            }
                        }
                        if (!identical) break;
                    }
                    if (identical) count++;
                }
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

