import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int U = sc.nextInt();
        int V = sc.nextInt();
        int W = sc.nextInt();
        int X = sc.nextInt();
        int K = sc.nextInt();
        int[][] A = new int[U][V];
        int[][] B = new int[W][X];
        for (int i = 0; i < U; i++) {
            for (int j = 0; j < V; j++) {
                A[i][j] = sc.nextInt();
            }
        }
        for (int i = 0; i < W; i++) {
            for (int j = 0; j < X; j++) {
                B[i][j] = sc.nextInt();
            }
        }
        int count = 0;
        for (int i = 0; i <= U - K; i++) {
            for (int j = 0; j <= V - K; j++) {
                for (int x = 0; x <= W - K; x++) {
                    for (int y = 0; y <= X - K; y++) {
                        int identical = 1;
                        for (int k = 0; k < K; k++) {
                            for (int l = 0; l < K; l++) {
                                if (A[i + k][j + l] != B[x + k][y + l]) {
                                    identical = 0;
                                    break;
                                }
                            }
                            if (identical == 0) break;
                        }
                        if (identical == 1) count++;
                    }
                }
            }
        }
        System.out.println(count);
    }
}

